import 'package:dartz/dartz.dart'; import 'package:injectable/injectable.dart'; import '../../repositories/i_message_repository.dart'; @injectable class SendMessageUseCase { final IMessageRepository _repo; SendMessageUseCase(this._repo); Future<Either<String, void>> call({required String sessionId, required String text, required String senderId, required String senderName}) => _repo.sendMessage(sessionId: sessionId, text: text, senderId: senderId, senderName: senderName); }
